/* Enable 'font-optical-sizing' on your body or root element */
body {
  font-family: 'Merriweather Sans Variable', sans-serif; /* Example variable font */
  font-optical-sizing: auto;
  /* 'auto' tells the browser to apply optical sizing based on font-size */
}

/* No further CSS needed for individual elements; 
   the browser handles adjustments automatically based on their font-size */
h1 {
  font-size: 3rem;
}

p {
  font-size: 1rem;
}

p {
  -webkit-hyphens: auto;
  -ms-hyphens: auto;
  hyphens: auto;
  text-align: justify;
  hyphenate-limit-chars: 6 3 2; /* min-chars-in-word min-chars-before min-chars-after */
  hyphenate-limit-lines: 2; /* Number of consecutive hyphenated lines */
  hyphenate-limit-last: always; /* Prevent hyphenation on the last line of a block */
}

/* Example for specific language */
html[lang="de"] {
  hyphens: manual; /* Or use 'auto' for browser defaults based on language */
}

.text-with-features {
  font-family: 'Merriweather', serif; /* Choose a font known for OpenType features */
  /* Enable standard ligatures ('liga') and old-style numerals ('onum') */
  font-feature-settings: "liga", "onum";
  /* For older browsers (especially WebKit before full support) */
  -webkit-font-feature-settings: "liga", "onum";
}

/* Example of enabling fractions ('frac') */
.fraction-text {
  font-family: 'Open Sans', sans-serif;
  font-feature-settings: "frac";
  -webkit-font-feature-settings: "frac";
}

a {
  text-decoration: underline; /* Ensure underline is present */
  text-underline-offset: 0.2em; /* Adjusts vertical position to avoid descenders */
  text-decoration-thickness: 0.08em; /* Sets initial thickness */
  text-decoration-color: var(--primary-color, currentColor); /* Optional: customize color */
  transition: text-decoration-color 0.2s ease-in-out, text-decoration-thickness 0.2s ease-in-out;
}

a:hover {
  text-decoration-thickness: 0.15em; /* Thicker on hover for subtle interaction */
}

h1, .headline {
  text-wrap: balance;
}

@font-face {
    font-family: 'Inter Variable';
    src: url('/fonts/Inter-roman.var.woff2') format('woff2-variations');
    font-weight: 100 900; /* Range of weights available */
    font-stretch: 25% 150%; /* Range of widths available */
    font-style: normal;
}

body {
    font-family: 'Inter Variable', sans-serif;
    /* Set default weight (wght) and slant (slnt) */
    font-variation-settings: "wght" 400, "slnt" 0;
}

h1 {
    /* Custom weight and negative slant for a distinct heading */
    font-variation-settings: "wght" 750, "slnt" -7;
    font-weight: 750; /* Fallback/hint for non-variable font support */
}

p.caption {
    /* Lighter weight, narrower width for captions */
    font-variation-settings: "wght" 300, "wdth" 85;
    font-weight: 300; /* Fallback/hint */
    font-stretch: 85%; /* Fallback/hint */
}

body {
