:root {
  --base-font-size: 1.125rem; /* 18px base font size */
  --base-line-height-factor: 1.6; /* A common line-height factor */
  /* The core unit for vertical rhythm, derived from body's line-height */
  --baseline-unit: calc(var(--base-font-size) * var(--base-line-height-factor)); /* Approx 28.8px */
}

body {
  font-family: 'Inter', sans-serif;
  font-size: var(--base-font-size);
  line-height: var(--base-line-height-factor);
}

/* Apply the baseline unit to vertical margins for consistent spacing */
h1, h2, h3, h4, h5, h6, p, ul, ol, blockquote, figure {
  margin-top: 0;
  margin-bottom: var(--baseline-unit); /* All elements get one baseline unit of space below */
}

