  margin-bottom: var(--baseline-unit); /* 1 baseline unit below H1 */
}

h2 {
  font-size: 1.75rem; /* ~28px */
  line-height: 1.3;
  margin-top: var(--baseline-unit); /* 1 baseline unit above H2 */
  margin-bottom: var(--baseline-unit);
}

